//! Integration tests for MambaPipeline (Mamba-1 S6 + Mamba-2/FalconMamba SSD).
//!
//! Uses tiny synthetic dimensions so tests run in-process with no I/O.

use distributed_inference::loader::{KnotConfig, OwnedBytes, TensorInfo, WeightBackend};
use distributed_inference::model_mamba::{MambaConfig, MambaPipeline};
use std::any::Any;
use std::collections::HashMap;
use std::sync::Arc;

// ─────────────────────────────────────────────────────────────────────────────
// Minimal mock backend backed by a HashMap<name, raw F32 bytes>
// ─────────────────────────────────────────────────────────────────────────────

struct MockBackend {
    store: HashMap<String, Vec<u8>>,
}

impl MockBackend {
    fn new() -> Self {
        Self {
            store: HashMap::new(),
        }
    }

    fn insert_f32(&mut self, name: &str, v: Vec<f32>) {
        let bytes: Vec<u8> = v.iter().flat_map(|f| f.to_le_bytes()).collect();
        // Accept both bare-name and bare-name + ".bin" variants so lookup is forgiving
        self.store.insert(name.to_string(), bytes.clone());
        self.store.insert(format!("{name}.bin"), bytes);
    }

    fn fill_f32(&mut self, name: &str, n: usize, seed: f32) {
        let v: Vec<f32> = (0..n).map(|i| (i as f32 * seed).sin() * 0.1).collect();
        self.insert_f32(name, v);
    }

    fn into_arc(self) -> Arc<dyn WeightBackend> {
        Arc::new(self)
    }
}

unsafe impl Send for MockBackend {}
unsafe impl Sync for MockBackend {}

impl WeightBackend for MockBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        // Try with and without .bin suffix
        let key = if self.store.contains_key(name) {
            name.to_string()
        } else {
            let bare = name.strip_suffix(".bin").unwrap_or(name);
            if self.store.contains_key(bare) {
                bare.to_string()
            } else {
                return Err(format!("MockBackend: missing tensor {name:?}"));
            }
        };
        Ok(OwnedBytes::Owned(Arc::new(self.store[&key].clone())))
    }

    fn has_tensor(&self, name: &str) -> bool {
        self.store.contains_key(name)
            || self
                .store
                .contains_key(name.strip_suffix(".bin").unwrap_or(name))
    }

    fn as_any(&self) -> &dyn Any {
        self
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Builder helpers
// ─────────────────────────────────────────────────────────────────────────────

const D: usize = 32; // hidden_dim
const DI: usize = 64; // d_inner = 2 * D
const DS: usize = 4; // d_state
const DCONV: usize = 4;
const DT_RANK: usize = 8;
const VOCAB: usize = 64;
const LAYERS: usize = 2;

fn mamba1_knot_config() -> KnotConfig {
    serde_json::from_str(&format!(
        r#"{{
        "hidden_dim": {D}, "num_layers": {LAYERS}, "num_heads": 1, "num_kv_heads": 1,
        "head_dim": {D}, "intermediate_size": {DI}, "vocab_size": {VOCAB},
        "arch": "mamba",
        "d_state": {DS}, "d_conv": {DCONV}, "ssm_expand": 2, "dt_rank": {DT_RANK}
    }}"#
    ))
    .unwrap()
}

fn mamba2_knot_config() -> KnotConfig {
    serde_json::from_str(&format!(
        r#"{{
        "hidden_dim": {D}, "num_layers": {LAYERS}, "num_heads": 1, "num_kv_heads": 1,
        "head_dim": {D}, "intermediate_size": {DI}, "vocab_size": {VOCAB},
        "arch": "falcon-mamba",
        "d_state": {DS}, "d_conv": {DCONV}, "ssm_expand": 2
    }}"#
    ))
    .unwrap()
}

/// Populate a MockBackend with all tensors required for a 2-layer Mamba-1 pipeline.
fn build_mamba1_backend() -> MockBackend {
    let mut b = MockBackend::new();
    b.fill_f32("token_embd_weight", VOCAB * D, 0.01);
    b.fill_f32("output_norm_weight", D, 0.1);
    b.fill_f32("output_weight", VOCAB * D, 0.02);

    for l in 0..LAYERS {
        let n = |s: &str| format!("blk_{l}_{s}");

        b.fill_f32(&n("norm_weight"), D, 0.05);
        b.fill_f32(&n("ssm_in_proj_weight"), DI * 2 * D, 0.03);
        // conv1d weight: [d_conv, d_inner]
        b.fill_f32(&n("ssm_conv1d_weight"), DCONV * DI, 0.02);
        b.fill_f32(&n("ssm_conv1d_bias"), DI, 0.001);
        // Mamba-1 specific
        b.fill_f32(&n("ssm_x_proj_weight"), (DT_RANK + 2 * DS) * DI, 0.02);
        b.fill_f32(&n("ssm_dt_proj_weight"), DI * DT_RANK, 0.02);
        b.fill_f32(&n("ssm_dt_proj_bias"), DI, 0.001);
        b.fill_f32(&n("ssm_a_log"), DI * DS, -0.1);
        b.fill_f32(&n("ssm_d"), DI, 1.0);
        b.fill_f32(&n("ssm_out_proj_weight"), D * DI, 0.02);
    }
    b
}

fn build_mamba2_backend() -> MockBackend {
    let mut b = MockBackend::new();
    b.fill_f32("token_embd_weight", VOCAB * D, 0.01);
    b.fill_f32("output_norm_weight", D, 0.1);
    b.fill_f32("output_weight", VOCAB * D, 0.02);

    for l in 0..LAYERS {
        let n = |s: &str| format!("blk_{l}_{s}");

        b.fill_f32(&n("norm_weight"), D, 0.05);
        b.fill_f32(&n("ssm_in_proj_weight"), DI * 2 * D, 0.03);
        b.fill_f32(&n("ssm_conv1d_weight"), DCONV * DI, 0.02);
        b.fill_f32(&n("ssm_conv1d_bias"), DI, 0.001);
        // Mamba-2: a_log is [d_state] diagonal, plus dt_bias
        b.fill_f32(&n("ssm_a_log"), DS, -0.1);
        b.fill_f32(&n("ssm_dt_bias"), DI, 0.001);
        b.fill_f32(&n("ssm_d"), DI, 1.0);
        b.fill_f32(&n("ssm_out_proj_weight"), D * DI, 0.02);
    }
    b
}

// ─────────────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────────────

#[test]
fn mamba_config_from_knot_config_mamba1() {
    let cfg = MambaConfig::from_knot(&mamba1_knot_config());
    assert_eq!(cfg.hidden_dim, D);
    assert_eq!(cfg.num_layers, LAYERS);
    assert_eq!(cfg.vocab_size, VOCAB);
    assert_eq!(cfg.d_inner, DI);
    assert_eq!(cfg.d_state, DS);
    assert_eq!(cfg.d_conv, DCONV);
    assert_eq!(cfg.dt_rank, Some(DT_RANK));
    assert_eq!(cfg.arch, "mamba");
}

#[test]
fn mamba_config_from_knot_config_mamba2() {
    let cfg = MambaConfig::from_knot(&mamba2_knot_config());
    assert_eq!(cfg.d_inner, DI);
    assert_eq!(cfg.d_state, DS);
    assert_eq!(cfg.dt_rank, None); // Mamba-2 has no dt_rank
    assert_eq!(cfg.arch, "falcon-mamba");
}

#[test]
fn knot_config_ssm_fields_roundtrip() {
    let json = r#"{
        "hidden_dim": 2560, "num_layers": 64, "num_heads": 1, "num_kv_heads": 1,
        "head_dim": 2560, "intermediate_size": 5120, "vocab_size": 50280,
        "arch": "mamba", "d_state": 16, "d_conv": 4, "ssm_expand": 2, "dt_rank": 160
    }"#;
    let cfg: KnotConfig = serde_json::from_str(json).unwrap();
    assert_eq!(cfg.d_state, Some(16));
    assert_eq!(cfg.d_conv, Some(4));
    assert_eq!(cfg.ssm_expand, Some(2));
    assert_eq!(cfg.dt_rank, Some(160));
    // Transformer fields should default gracefully
    assert_eq!(cfg.final_logit_softcap, None);
    assert_eq!(cfg.sliding_window, None);
}

#[test]
fn knot_config_ssm_fields_default_when_absent() {
    // A standard transformer KnotConfig must still parse without SSM fields.
    let json = r#"{
        "hidden_dim": 4096, "num_layers": 32, "num_heads": 32, "num_kv_heads": 8,
        "head_dim": 128, "intermediate_size": 14336, "vocab_size": 32000
    }"#;
    let cfg: KnotConfig = serde_json::from_str(json).unwrap();
    assert_eq!(cfg.d_state, None);
    assert_eq!(cfg.d_conv, None);
    assert_eq!(cfg.ssm_expand, None);
    assert_eq!(cfg.dt_rank, None);
    assert_eq!(cfg.rwkv_n_heads, None);
}

#[test]
fn mamba1_pipeline_forward_produces_finite_logits() {
    let cfg = mamba1_knot_config();
    let backend = build_mamba1_backend().into_arc();
    let mut pipeline = MambaPipeline::from_knot(&cfg, backend);

    let mut logits = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut logits);

    assert_eq!(logits.len(), VOCAB);
    assert!(
        logits.iter().all(|v| v.is_finite()),
        "logits contain NaN/Inf"
    );
}

#[test]
fn mamba1_pipeline_state_changes_across_tokens() {
    let cfg = mamba1_knot_config();
    let backend = build_mamba1_backend().into_arc();
    let mut pipeline = MambaPipeline::from_knot(&cfg, backend);

    let mut logits_tok0 = vec![0.0f32; VOCAB];
    let mut logits_tok1 = vec![0.0f32; VOCAB];

    pipeline.forward_one(0, &mut logits_tok0);
    pipeline.forward_one(1, &mut logits_tok1);

    // After two different tokens the outputs must differ (state is recurrent)
    let changed = logits_tok0
        .iter()
        .zip(&logits_tok1)
        .any(|(a, b)| (a - b).abs() > 1e-6);
    assert!(
        changed,
        "Logits identical across tokens — recurrent state not updating"
    );
}

#[test]
fn mamba1_pipeline_reset_states_reproduces_first_output() {
    let cfg = mamba1_knot_config();
    let backend = build_mamba1_backend().into_arc();
    let mut pipeline = MambaPipeline::from_knot(&cfg, backend);

    let mut out_first = vec![0.0f32; VOCAB];
    let mut out_mid = vec![0.0f32; VOCAB];
    let mut out_reset = vec![0.0f32; VOCAB];

    pipeline.forward_one(0, &mut out_first);
    pipeline.forward_one(1, &mut out_mid);
    pipeline.reset_states();
    pipeline.forward_one(0, &mut out_reset);

    // After reset + same token, output must match the first run exactly.
    for (a, b) in out_first.iter().zip(&out_reset) {
        assert!((a - b).abs() < 1e-5, "reset + replay mismatch: {a} vs {b}");
    }
    // Mid-run output must differ from both.
    let mid_differs = out_first
        .iter()
        .zip(&out_mid)
        .any(|(a, b)| (a - b).abs() > 1e-6);
    assert!(mid_differs, "Mid-run output should differ from first");
}

#[test]
fn mamba2_pipeline_forward_produces_finite_logits() {
    let cfg = mamba2_knot_config();
    let backend = build_mamba2_backend().into_arc();
    let mut pipeline = MambaPipeline::from_knot(&cfg, backend);

    let mut logits = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut logits);

    assert_eq!(logits.len(), VOCAB);
    assert!(
        logits.iter().all(|v| v.is_finite()),
        "Mamba-2 logits contain NaN/Inf"
    );
}

#[test]
fn mamba2_pipeline_state_changes_across_tokens() {
    let cfg = mamba2_knot_config();
    let backend = build_mamba2_backend().into_arc();
    let mut pipeline = MambaPipeline::from_knot(&cfg, backend);

    let mut l0 = vec![0.0f32; VOCAB];
    let mut l1 = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut l0);
    pipeline.forward_one(2, &mut l1);

    let changed = l0.iter().zip(&l1).any(|(a, b)| (a - b).abs() > 1e-6);
    assert!(changed, "Mamba-2 logits identical across tokens");
}
